        function StockDashboard() {
            const stockData = [
                { symbol: 'AAPL', price: 150.10 },
                { symbol: 'GOOGL', price: 2735.20 }
            ];

            const news = [
                { text: 'Market opens mixed amid economic uncertainty' },
                { text: 'Tech stocks rally on earnings beat' }
            ];

            // Chart dimensions and data mapping (based on screenshot values)
            const yMin = 0;
            const yMax = 2800;
            const yTicks = [0, 700, 1400, 2100, 2800]; // Y-axis tick values

            // Calculate line coordinates
            const chartWidth = 100; // percent
            const chartHeight = 100; // percent
            const getPointY = (price) => {
                // Map price to vertical position (0% at bottom, 100% at top)
                const normalized = (price - yMin) / (yMax - yMin);
                return 100 - (normalized * 100); // invert for SVG coordinate system
            };

            const lineData = stockData.map((stock, index) => ({
                x: index === 0 ? 0 : 100, // Percentage from left: 0% for first stock, 100% for second
                y: getPointY(stock.price),
                price: stock.price
            }));

            return (
                <div className="dashboard-container">
                    <div className="price-panel">
                        {stockData.map((stock, index) => (
                            <div key={stock.symbol}>
                                {stock.symbol}: ${stock.price.toFixed(2)}
                            </div>
                        ))}
