                        <div className="chart-area">
                            <div className="chart-y-axis">
                                {yTicks.reverse().map(tick => (
                                    <div key={tick}>{tick}</div>
                                ))}
                            </div>
                            <div className="chart-grid">
                                {yTicks.map(tick => (
                                    <div key={tick} className="grid-line" style={{ bottom: `${getPointY(tick)}%` }}></div>
                                ))}
                                <svg className="line-chart" viewBox="0 0 100 100" preserveAspectRatio="none">
                                    <polyline
                                        points={lineData.map(p => `${p.x},${p.y}`).join(' ')}
                                        fill="none"
                                        stroke="#6666ff"
                                        strokeWidth="0.5"
                                        vectorEffect="non-scaling-stroke"
                                    />
                                </svg>
                            </div>
                            <div className="chart-x-axis">
                                {stockData.map(stock => (
                                    <div key={stock.symbol}>{stock.symbol}</div>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="news-panel">
                        {news.map((item, index) => (
                            <div key={index} className={index === 0 ? 'news-headline' : 'news-sub-headline'}>
                                {item.text}
                            </div>
                        ))}
                    </div>
                </div>
            );
        }

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<StockDashboard />);
