    <script type="text/babel">
        function SpeedTestApp() {
            const [downloadSpeed, setDownloadSpeed] = React.useState(0);
            const [uploadSpeed, setUploadSpeed] = React.useState(0);
            const [isTesting, setIsTesting] = React.useState(false);

            const simulateSpeedTest = () => {
                if (isTesting) return;

                setIsTesting(true);
                setDownloadSpeed(0);
                setUploadSpeed(0);

                // Simulate download speed test
                let downloadProgress = 0;
                const downloadInterval = setInterval(() => {
                    downloadProgress += Math.random() * 5 + 1;
                    if (downloadProgress >= 100) {
                        clearInterval(downloadInterval);
                        setDownloadSpeed(Math.floor(Math.random() * 50 + 10));

                        // Start upload test after download
                        setTimeout(() => {
                            let uploadProgress = 0;
                            const uploadInterval = setInterval(() => {
                                uploadProgress += Math.random() * 4 + 0.5;
                                if (uploadProgress >= 100) {
                                    clearInterval(uploadInterval);
                                    setUploadSpeed(Math.floor(Math.random() * 20 + 5));
                                    setIsTesting(false);
                                } else {
                                    setUploadSpeed(Math.floor((uploadProgress / 100) * (Math.random() * 15 + 3)));
                                }
                            }, 50);
                        }, 500);
                    } else {
                        setDownloadSpeed(Math.floor((downloadProgress / 100) * (Math.random() * 60 + 15)));
                    }
                }, 50);
            };

            return (
                <React.Fragment>
                    <div className={`speed-display ${isTesting ? 'testing' : ''}`}>
                        <div className="speed-text">
                            download speed: {downloadSpeed} Mbps<br />
                            upload speed: {uploadSpeed} Mbps
                        </div>
                    </div>
                    <button 
                        className="test-button"
                        onClick={simulateSpeedTest}
                        disabled={isTesting}
                    >
                        test internet speed
                    </button>
                </React.Fragment>
            );
        }

        ReactDOM.render(<SpeedTestApp />, document.getElementById('root'));
    </script>
</body>
</html>
